/*
 * Bootloader Simulation in C
 * Demonstrates the conceptual structure of a bootloader
 * and how it loads the OS kernel from disk.
 * 
 * This is an educational simulation - real bootloaders
 * operate in 16-bit real mode and are written in assembly.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

/* Constants */
#define SECTOR_SIZE 512
#define KERNEL_MAX_SIZE (10 * 1024 * 1024) /* 10 MB max kernel */
#define MAX_BOOT_ARGS 256

/* Bootloader stage definitions */
typedef enum {
 STAGE_1, /* In MBR - tiny (446 bytes) */
 STAGE_1_5, /* In disk gap - filesystem drivers */
 STAGE_2 /* In /boot - full menu system */
} BootStage;

/* Boot configuration */
typedef struct {
 char kernel_path[256];
 char initrd_path[256];
 char root_device[32];
 char boot_args[MAX_BOOT_ARGS];
 uint32_t kernel_load_addr;
 uint32_t initrd_load_addr;
} BootConfig;

/* Simulated disk sector */
typedef struct {
 uint8_t data[SECTOR_SIZE];
} DiskSector;

/* Partition table entry (simplified MBR) */
typedef struct {
 uint8_t status; /* 0x80 = bootable, 0x00 = not */
 uint8_t start_head;
 uint16_t start_sector_cyl;
 uint8_t partition_type;
 uint8_t end_head;
 uint16_t end_sector_cyl;
 uint32_t lba_start;
 uint32_t sector_count;
} __attribute__((packed)) PartitionEntry;

/* Simulated memory for loading kernel */
typedef struct {
 uint8_t *memory;
 size_t size;
 size_t used;
} SimulatedRAM;

/* Function prototypes */
void simulate_post(void);
void read_mbr(DiskSector *mbr, PartitionEntry *partitions);
void load_bootloader_stage(SimulatedRAM *ram, BootStage stage);
void load_kernel(SimulatedRAM *ram, const char *kernel_file, uint32_t load_addr);
void load_initrd(SimulatedRAM *ram, const char *initrd_file, uint32_t load_addr);
void setup_boot_parameters(BootConfig *config);
void jump_to_kernel(uint32_t kernel_addr, const BootConfig *config);

/* Simulated POST (Power-On Self-Test) */
void simulate_post(void) {
 printf("=== POST (Power-On Self-Test) ===\n");
 printf("[✓] CPU registers test passed\n");
 printf("[✓] BIOS firmware integrity verified\n");
 printf("[✓] Memory test: 16384 MB detected\n");
 printf("[✓] Keyboard initialized\n");
 printf("[✓] Display adapter detected: VGA compatible\n");
 printf("[✓] Storage devices detected:\n");
 printf(" - /dev/sda: 500 GB (SSD)\n");
 printf(" - /dev/sdb: Not detected\n");
 printf("[✓] USB controllers initialized\n");
 printf("[✓] Network controller detected\n");
 printf("[✓] POST completed successfully\n\n");
}

/* Simulate reading MBR from disk */
void read_mbr(DiskSector *mbr, PartitionEntry *partitions) {
 printf("=== Reading MBR from boot device ===\n");
 printf("Reading sector 0 from /dev/sda...\n");

 /* Simulate MBR content */
 memset(mbr->data, 0, SECTOR_SIZE);
 mbr->data[510] = 0x55; /* Boot signature */
 mbr->data[511] = 0xAA;

 /* Simulate partition table */
 partitions[0].status = 0x80; /* Bootable */
 partitions[0].partition_type = 0x83; /* Linux */
 partitions[0].lba_start = 2048;
 partitions[0].sector_count = 104857600; /* 50 GB */

 partitions[1].status = 0x00;
 partitions[1].partition_type = 0x07; /* NTFS/Windows */
 partitions[1].lba_start = 104860648;
 partitions[1].sector_count = 104857600; /* 50 GB */

 printf("Found active partition: Linux (sda1)\n");
 printf("Bootloader location: LBA %u\n\n", partitions[0].lba_start);
}

/* Simulate loading bootloader stages */
void load_bootloader_stage(SimulatedRAM *ram, BootStage stage) {
 const char *stage_name[] = {"Stage 1", "Stage 1.5", "Stage 2"};

 printf("=== Loading GRUB %s ===\n", stage_name[stage]);

 switch(stage) {
 case STAGE_1:
 printf("Stage 1: Loading from MBR (446 bytes)\n");
 printf(" - Minimal code to find Stage 1.5\n");
 printf(" - Location: 1st sector of disk\n");
 break;
 case STAGE_1_5:
 printf("Stage 1.5: Loading filesystem drivers\n");
 printf(" - Contains ext4, NTFS, FAT drivers\n");
 printf(" - Can now read /boot partition\n");
 printf(" - Location: Sectors after MBR\n");
 break;
 case STAGE_2:
 printf("Stage 2: Loading full GRUB menu\n");
 printf(" - Reads /boot/grub/grub.cfg\n");
 printf(" - Displays boot menu\n");
 printf(" - Allows kernel selection\n");
 printf(" - Location: /boot/grub/\n");
 break;
 }

 /* Simulate loading into memory */
 printf(" - Loading into memory at 0x%x\n", 0x100000 + (stage * 0x1000));
 printf(" - %s loaded successfully\n\n", stage_name[stage]);
}

/* Simulate kernel loading */
void load_kernel(SimulatedRAM *ram, const char *kernel_file, uint32_t load_addr) {
 printf("=== Loading Linux Kernel ===\n");
 printf("Kernel: %s\n", kernel_file);
 printf("Load address: 0x%08X\n", load_addr);
 printf("Decompressing kernel... ");

 /* Simulate decompression */
 for(int i = 0; i < 3; i++) {
 printf(".");
 fflush(stdout);
 usleep(100000);
 }
 printf("done\n");

 printf("Kernel loaded and decompressed\n");
 printf(" - CPU mode: 64-bit protected mode\n");
 printf(" - Memory management initialized\n");
 printf(" - Interrupt descriptor table set up\n");
 printf(" - Device drivers loading...\n");
 printf("\n");
}

/* Simulate initrd loading */
void load_initrd(SimulatedRAM *ram, const char *initrd_file, uint32_t load_addr) {
 printf("=== Loading Initial RAM Disk (initrd) ===\n");
 printf("initrd: %s\n", initrd_file);
 printf("Load address: 0x%08X\n", load_addr);
 printf("Contains: essential drivers, boot scripts\n");
 printf("Purpose: Mount real root filesystem\n\n");
}

/* Setup boot parameters to pass to kernel */
void setup_boot_parameters(BootConfig *config) {
 printf("=== Setting Boot Parameters ===\n");
 strcpy(config->kernel_path, "/boot/vmlinuz-5.15.0");
 strcpy(config->initrd_path, "/boot/initrd.img-5.15.0");
 strcpy(config->root_device, "/dev/sda1");
 strcpy(config->boot_args, "quiet splash");
 config->kernel_load_addr = 0x100000;
 config->initrd_load_addr = 0x2000000;

 printf("Boot parameters prepared:\n");
 printf(" root=%s\n", config->root_device);
 printf(" kernel=%s\n", config->kernel_path);
 printf(" initrd=%s\n", config->initrd_path);
 printf(" args=%s\n", config->boot_args);
 printf("\n");
}

/* Simulate jumping to kernel */
void jump_to_kernel(uint32_t kernel_addr, const BootConfig *config) {
 printf("=== Transferring Control to Kernel ===\n");
 printf("Jumping to: 0x%08X\n", kernel_addr);
 printf("Registers set:\n");
 printf(" AX = 0 (boot success)\n");
 printf(" BX = pointer to boot_params\n");
 printf(" SI = initrd address\n");
 printf("\n");
 printf("*** KERNEL TAKES OVER ***\n\n");
}

/* Main simulation */
int main(void) {
 DiskSector mbr;
 PartitionEntry partitions[4];
 SimulatedRAM ram;
 BootConfig config;

 printf("\n");
 printf("╔═══════════════════════════════════════════════════╗\n");
 printf("║ SYSTEM BOOT PROCESS SIMULATION ║\n");
 printf("╚═══════════════════════════════════════════════════╝\n\n");

 /* Step 1: POST */
 simulate_post();

 /* Step 2: Read MBR and find bootloader */
 read_mbr(&mbr, partitions);

 /* Step 3: Load GRUB stages */
 load_bootloader_stage(&ram, STAGE_1);
 load_bootloader_stage(&ram, STAGE_1_5);
 load_bootloader_stage(&ram, STAGE_2);

 /* Step 4: User selects kernel from menu (simulated) */
 printf("=== Boot Menu ===\n");
 printf(" 1. Ubuntu Linux (default)\n");
 printf(" 2. Windows 10\n");
 printf(" 3. Advanced options\n\n");
 printf("Selected: 1 (Ubuntu Linux)\n\n");

 /* Step 5: Load kernel and initrd */
 setup_boot_parameters(&config);
 load_kernel(&ram, config.kernel_path, config.kernel_load_addr);
 load_initrd(&ram, config.initrd_path, config.initrd_load_addr);

 /* Step 6: Jump to kernel */
 jump_to_kernel(config.kernel_load_addr, &config);

 /* Step 7: Kernel starts init */
 printf("=== Kernel Starting Init Process ===\n");
 printf("PID 1 process starting: /sbin/init\n");
 printf("Loading system services (systemd)...\n");
 printf(" [ OK ] Started Network Service\n");
 printf(" [ OK ] Started Disk Manager\n");
 printf(" [ OK ] Started Display Manager\n");
 printf("\n");

 printf("╔═══════════════════════════════════════════════════╗\n");
 printf("║ BOOT COMPLETE ║\n");
 printf("║ Welcome to Ubuntu 22.04 ║\n");
 printf("╚═══════════════════════════════════════════════════╝\n");

 return 0;
}
